custom_css:
@import url('https://fonts.googleapis.com/css2?family=Yeseva+One&family=Lato:wght@300;400;700&display=swap');

/* Typography */
body, .button, button, input, select, textarea { font-family: 'Lato', arial, sans-serif !important; }
h1, h2, h3, h4, h5, h6, .site-title, .entry-title, .woocommerce-loop-product__title { font-family: 'Yeseva One', Georgia, serif !important; font-weight: 400 !important; letter-spacing: 0.01em; }

/* Base layout */
body { background-color: #ffffff !important; color: #333 !important; }
.site-header, .site-footer, .woocommerce-store-notice { background-color: #161616 !important; }
.site-header *, .site-footer *, .woocommerce-store-notice * { color: #F7F7F7 !important; }
.site-header a:hover { opacity: 0.7; }
.site-content { background-color: #ffffff !important; color: #333 !important; }
.entry-title, .woocommerce-loop-product__title, h1, h2, h3 { color: #222 !important; }

/* Promo banner pinned top, like GoDaddy */
.woocommerce-store-notice { position: relative !important; bottom: auto !important; text-align: center; padding: 0.6em 1em; font-size: 0.9em; letter-spacing: 0.04em; }
.woocommerce-store-notice__dismiss-link { display: none !important; }

/* Buttons */
.button, button, .woocommerce a.button, .woocommerce button.button, input[type="submit"] { 
  border-radius: 0 !important; 
  letter-spacing: 0.05em;
  text-transform: uppercase;
  padding: 0.85em 1.6em;
}
.woocommerce a.button, .woocommerce button.button { background: #161616 !important; color: #fff !important; border: 1px solid #161616 !important; }
.woocommerce a.button:hover, .woocommerce button.button:hover { background: #fff !important; color: #161616 !important; }

/* Product cards */
.woocommerce ul.products li.product { 
  text-align: center; 
  background: #fafafa; 
  padding: 1.5em 1em; 
  transition: box-shadow 0.2s ease, transform 0.2s ease;
}
.woocommerce ul.products li.product:hover { 
  box-shadow: 0 8px 24px rgba(0,0,0,0.08); 
  transform: translateY(-2px); 
}
.woocommerce ul.products li.product img { transition: opacity 0.2s ease; }
.woocommerce ul.products li.product:hover img { opacity: 0.85; }

/* Product title + price */
.woocommerce ul.products li.product .woocommerce-loop-product__title { 
  font-size: 1.05em !important; 
  margin-top: 0.5em; 
  margin-bottom: 0.3em; 
  min-height: 2.6em; 
}
.woocommerce ul.products li.product .price, .price { 
  color: #161616 !important; 
  font-weight: 700 !important; 
  font-family: 'Lato', sans-serif !important; 
  font-size: 1.1em;
}

/* Hide Storefront's "Add to cart" button on product loop (GoDaddy doesn't show one inline); rely on hover Quick View */
.woocommerce ul.products li.product .button { 
  margin-top: 0.8em; 
  font-size: 0.85em;
  background: transparent !important;
  color: #161616 !important;
  border: 1px solid #161616 !important;
}
.woocommerce ul.products li.product .button:hover { background: #161616 !important; color: #fff !important; }

/* Section headings centered + bigger */
.site-content h2, .woocommerce-products-header h1 { 
  font-size: 2.2em !important; 
  text-align: center; 
  margin: 1.8em 0 1em; 
  letter-spacing: 0.02em;
}

/* Footer minimal */
.site-footer { padding: 2.5em 0 !important; border-top: 1px solid #2a2a2a; }
.site-footer .col-full { text-align: center; }

/* Hero block (homepage) — make h2 'Featured Products' first heading look like a hero */
.home .site-content > .post:first-child .entry-title, .home .hentry .entry-title { display: none; }

/* Category cards on homepage */
.woocommerce .wc-block-product-categories img, .woocommerce-page .product-category img { display: block; margin: 0 auto; }
